 1	import * as React from 'react';
 2	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 3	
 4	import { useBoolean } from './useBoolean';
 5	import Popover from '../components/Popover';
 6	
 7	const POPOVER_ID = 'plugin__lightspeed-console-plugin__POPOVER_ID';
 8	
 9	const usePopover = () => {
10	  const [isLaunched, , setLaunched] = useBoolean(false);
11	
12	  const launchModal = useModal();
13	
14	  React.useEffect(() => {
15	    if (!isLaunched && launchModal) {
16	      // @ts-expect-error: The plugin SDK expects launchModal to take 2 arguments, but depending on
